import os
import requests

# Load once at import time — fails fast if the variable is missing
_API_KEY = os.environ["WEATHER_API_KEY"]

def get_weather(city: str) -> dict:
    """The model calls this; it never sees the key."""
    try:
        resp = requests.get(
            "https://api.weather.example.com/current",
            params={"city": city},
            headers={"X-API-Key": _API_KEY},
            timeout=(5, 10),
        )
        if resp.status_code == 401:
            return {"error": "AUTH_ERROR",
                    "message": "Weather API key is invalid or has been revoked"}
        if resp.status_code == 429:
            return {"error": "RATE_LIMITED",
                    "message": "Weather API rate limit reached",
                    "retry_after_seconds": int(resp.headers.get("Retry-After", 60))}
        resp.raise_for_status()
        d = resp.json()
        return {"city": city, "temperature_c": d["temp_c"], "condition": d["condition"]}
    except requests.Timeout:
        return {"error": "TIMEOUT", "message": "Weather service timed out",
                "retry_after_seconds": 10}
    except Exception as exc:
        return {"error": "SERVICE_UNAVAILABLE", "message": str(exc)}

import os, time, threading
import requests

_TOKEN_CACHE: dict[str, float | str] = {
    "access_token": "",
    "expires_at": 0.0,
}
_TOKEN_LOCK = threading.Lock()
_EXPIRY_BUFFER = 30   # refresh 30 s before actual expiry

def _get_access_token() -> str:
    """Return a valid access token, fetching a new one if needed."""
    with _TOKEN_LOCK:
        if time.time() < _TOKEN_CACHE["expires_at"] - _EXPIRY_BUFFER:
            return str(_TOKEN_CACHE["access_token"])

        resp = requests.post(
            os.environ["OAUTH_TOKEN_URL"],
            data={
                "grant_type": "client_credentials",
                "client_id": os.environ["OAUTH_CLIENT_ID"],
                "client_secret": os.environ["OAUTH_CLIENT_SECRET"],
                "scope": os.environ.get("OAUTH_SCOPE", ""),
            },
            timeout=(5, 10),
        )
        resp.raise_for_status()
        payload = resp.json()
        _TOKEN_CACHE["access_token"] = payload["access_token"]
        _TOKEN_CACHE["expires_at"] = time.time() + payload.get("expires_in", 3600)
        return str(_TOKEN_CACHE["access_token"])

def call_protected_api(endpoint: str, params: dict | None = None) -> dict:
    """Make an authenticated call; refresh the token on 401 and retry once."""
    for attempt in range(2):
        token = _get_access_token()
        try:
            resp = requests.get(
                f"{os.environ['API_BASE_URL']}{endpoint}",
                params=params or {},
                headers={"Authorization": f"Bearer {token}"},
                timeout=(5, 15),
            )
        except requests.Timeout:
            return {"error": "TIMEOUT", "message": "API timed out", "retry_after_seconds": 15}
        except Exception as exc:
            return {"error": "SERVICE_UNAVAILABLE", "message": str(exc)}

        if resp.status_code == 401 and attempt == 0:
            # Force a token refresh on the next iteration
            with _TOKEN_LOCK:
                _TOKEN_CACHE["expires_at"] = 0.0
            continue

        if resp.status_code >= 400:
            return {"error": "HTTP_ERROR", "status": resp.status_code,
                    "message": resp.text[:200]}
        return resp.json()
    return {"error": "AUTH_ERROR", "message": "Token refresh failed — check client credentials"}

import os, time, threading
import requests

_USER_TOKENS: dict[str, dict] = {}   # user_id → {access_token, refresh_token, expires_at}
_USER_LOCK = threading.Lock()

def _refresh_user_token(user_id: str) -> str:
    """Exchange a stored refresh token for a new access token."""
    with _USER_LOCK:
        stored = _USER_TOKENS.get(user_id)
        if not stored or not stored.get("refresh_token"):
            raise ValueError(f"No refresh token for user {user_id}. User must re-authorise.")

        resp = requests.post(
            os.environ["OAUTH_TOKEN_URL"],
            data={
                "grant_type": "refresh_token",
                "refresh_token": stored["refresh_token"],
                "client_id": os.environ["OAUTH_CLIENT_ID"],
                "client_secret": os.environ["OAUTH_CLIENT_SECRET"],
            },
            timeout=(5, 10),
        )
        resp.raise_for_status()
        payload = resp.json()
        stored["access_token"] = payload["access_token"]
        stored["expires_at"] = time.time() + payload.get("expires_in", 3600)
        if "refresh_token" in payload:   # some providers rotate the refresh token
            stored["refresh_token"] = payload["refresh_token"]
        return str(stored["access_token"])

def get_user_token(user_id: str) -> str:
    with _USER_LOCK:
        stored = _USER_TOKENS.get(user_id, {})
    if time.time() < stored.get("expires_at", 0) - 30:
        return str(stored["access_token"])
    return _refresh_user_token(user_id)

def list_calendar_events(user_id: str, date_from: str, date_to: str) -> dict:
    try:
        token = get_user_token(user_id)
    except ValueError as exc:
        return {"error": "AUTH_REQUIRED",
                "message": str(exc),
                "action": "redirect_user_to_oauth"}

    try:
        resp = requests.get(
            "https://www.googleapis.com/calendar/v3/calendars/primary/events",
            params={"timeMin": date_from, "timeMax": date_to, "maxResults": 20},
            headers={"Authorization": f"Bearer {token}"},
            timeout=(5, 15),
        )
    except requests.Timeout:
        return {"error": "TIMEOUT", "message": "Calendar API timed out", "retry_after_seconds": 10}

    if resp.status_code == 401:
        return {"error": "AUTH_ERROR",
                "message": "Access token rejected — user may need to re-authorise"}
    if resp.status_code >= 400:
        return {"error": "HTTP_ERROR", "status": resp.status_code, "message": resp.text[:200]}

    events = resp.json().get("items", [])
    return {
        "user_id": user_id,
        "date_from": date_from,
        "date_to": date_to,
        "event_count": len(events),
        "events": [
            {"id": e["id"], "title": e.get("summary", "(no title)"),
             "start": e.get("start", {}).get("dateTime"), "end": e.get("end", {}).get("dateTime")}
            for e in events
        ],
    }
